#ifndef FILEX_MAX_FDS
#define FILEX_MAX_FDS   16      /* max. Anzahl FileX-basierter FDs */
#endif

#ifndef FILEX_FIRST_FD
#define FILEX_FIRST_FD   3      /* 0,1,2 = stdin, stdout, stderr */
#endif

/* Timeout für Mutex-Zugriffe */
#ifndef FILEX_MUTEX_WAIT
#define FILEX_MUTEX_WAIT TX_WAIT_FOREVER
#endif

static_assert(FILEX_MAX_FDS < NX_BSD_SOCKFD_START, "FileX descriptors must be below sockets FDs");
static_assert(NX_BSD_SOCKFD_START >= 32, "invalid value for first BSD socket fd");

/* -------------------------------------------------------------
 * Globale Variablen
 * -----------------------------------------------------------*/

/* ThreadX-Mutex zum Schutz von FileX */
static TX_MUTEX g_filex_fs_mutex;

/* Eintrag in der FD-Tabelle */
typedef struct {
	FX_MEDIA *media;
    FX_FILE file;
    int     in_use;
    int     flags;     /* O_RDONLY/O_WRONLY/O_RDWR/... */
    char    name[FX_MAX_LONG_NAME_LEN + 1]; /* Name, z.B. für SEEK_END */
} filex_fd_t;

static filex_fd_t g_fd_table[FILEX_MAX_FDS];

static TX_MUTEX sys_lock_read;		// _read
static TX_MUTEX sys_lock_write;		// _write
static bool init_sys_lock_read = false;
static bool init_sys_lock_write = false;

/* -------------------------------------------------------------
 * Initialisierung
 * -----------------------------------------------------------*/

/*
 * Muss vom Applikationscode EINMALIG aufgerufen werden, nachdem
 *  - ThreadX gestartet und
 *  - FileX/Medium initialisiert ist.
 */
UINT filex_newlib_init(void)
{
    UINT status;

    status = tx_mutex_create(&g_filex_fs_mutex, "newlib_fs_mutex", TX_INHERIT);
    if (status != TX_SUCCESS) {
        return status;
    }

    /* FD-Tabelle zurücksetzen */
    memset(g_fd_table, 0x00, sizeof(g_fd_table));

    // Init mutexes for printf to linearize
    tx_mutex_create(&sys_lock_read, (CHAR*)"sys_lock_read", TX_INHERIT);
    tx_mutex_create(&sys_lock_write, (CHAR*)"sys_lock_write", TX_INHERIT);
    init_sys_lock_read = true;
    init_sys_lock_write = true;
    printf("Newlib: Init clib layer done.\n");
    return FX_SUCCESS;
}


/* -------------------------------------------------------------
 * Hilfsfunktionen
 * -----------------------------------------------------------*/

static int alloc_fd(void)
{
    for (int i = FILEX_FIRST_FD; i < FILEX_MAX_FDS; ++i) {
        if (!g_fd_table[i].in_use) {
            g_fd_table[i].in_use = 1;
            return i;
        }
    }
    return -1;
}

static void free_fd(int fd)
{
    if (fd >= FILEX_FIRST_FD && fd < FILEX_MAX_FDS) {
        g_fd_table[fd].in_use = 0;
        g_fd_table[fd].flags  = 0;
        g_fd_table[fd].name[0] = '\0';
    }
}

static int lock_fs(void)
{
    if (tx_mutex_get(&g_filex_fs_mutex, FILEX_MUTEX_WAIT) != TX_SUCCESS) {
        errno = EBUSY;
        return -1;
    }
    return 0;
}

static void unlock_fs(void)
{
    tx_mutex_put(&g_filex_fs_mutex);
}

/**
  * @brief  Retargets the C library printf function to the USART.
  * @param  None
  * @retval None
  */
int __io_putchar(int ch)
{
    if (ch == '\n') {
        uint8_t crlf[2] = {'\r','\n'};
        syscall_HAL_UART_write(crlf,2);
        return ch;
    }

  /* Place your implementation of putchar here */
  /* e.g. write a character to the USART1 and Loop until the end of transmission */
  syscall_HAL_UART_write( (uint8_t *) &ch, 1);
  return ch;
}

int __io_getchar(void)
{
	int ch;

	syscall_HAL_UART_read((uint8_t *)&ch);
	return ch;
}

