ssize_t _read(int fd, void *buf, size_t len)
{
  /* stdin/stdout/stderr -> hier z.B. auf UART routen */
  if (fd >= 0 && fd < FILEX_FIRST_FD) {
	  char * char_ptr = (char *) buf;

	  switch(fd)
	  {
	  case STDIN_FILENO:
		  if(init_sys_lock_read == true) tx_mutex_get(&sys_lock_read, TX_WAIT_FOREVER);
		  for (int iter = 0; iter < len; iter++)
		  {
			  *char_ptr++ = __io_getchar();
		  }
		  if(init_sys_lock_read == true) tx_mutex_put(&sys_lock_read);
		  return (ssize_t)len;
	  default:
		  return (ssize_t)-1;
	  }
  }


  if (fd >= FILEX_MAX_FDS || !g_fd_table[fd].in_use) {
      errno = EBADF;
      return -1;
  }

  //printf("Newlib: _read %d %p, %d\n", fd, buf, len);

  if (lock_fs() < 0) {
      return -1;
  }

  filex_fd_t *entry = &g_fd_table[fd];
  FX_FILE    *fx    = &entry->file;

  if (entry->media == NULL || buf == NULL) {
      errno = EINVAL;
      return -1;
  }

  ULONG bytes_read = 0;
  UINT  status     = fx_file_read(fx, buf, (ULONG)len, &bytes_read);

  unlock_fs();

  if ((status != FX_SUCCESS) && (status != FX_END_OF_FILE)) {
      errno = EIO;
      return -1;
  }

  return (ssize_t)bytes_read;
}

ssize_t _write(int fd, const void *buf, size_t len)
{
  /* stdin/stdout/stderr -> hier z.B. auf UART routen */
  if (fd >= 0 && fd < FILEX_FIRST_FD) {
	  char * char_ptr = (char *) buf;

	  switch(fd)
	  {
	  case STDOUT_FILENO:
	  case STDERR_FILENO:
		  if(init_sys_lock_write == true) tx_mutex_get(&sys_lock_write, TX_WAIT_FOREVER);
		  for (int iter = 0; iter < len; iter++)
		  {
		    __io_putchar(*char_ptr++);
		  }
		  if(init_sys_lock_write == true) tx_mutex_put(&sys_lock_write);
		  return (ssize_t)len;
	  default:
		  return (ssize_t)-1;
	  }
  }

  // Recursive Call to _write !!
  //printf("Newlib: _write %d %p, %d\n", fd, buf, len);

  if (fd < FILEX_FIRST_FD || fd >= FILEX_MAX_FDS || !g_fd_table[fd].in_use) {
      errno = EBADF;
      return -1;
  }

  if (lock_fs() < 0) {
      return -1;
  }

  filex_fd_t *entry = &g_fd_table[fd];
  FX_FILE    *fx    = &entry->file;

  if (entry->media == NULL || buf == NULL) {
      errno = EINVAL;
      return -1;
  }

  /* FileX schreibt i.d.R. ganz oder gar nicht */
  UINT status = fx_file_write(fx, (VOID *)buf, (ULONG)len);

  /* optional: flush hier oder erst beim close */
  /* fx_media_flush(entry->media); */

  unlock_fs();

  if (status != FX_SUCCESS) {
      errno = EIO;
      return -1;
  }

  return (ssize_t)len;
}

int _close(int fd)
{
  //printf("_close: fd=%d\n", file);

  // Check if fd belongs to BSD socket API
  if(fd >= NX_BSD_SOCKFD_START)
  {
	  // call socket close handler
	  return syscall_close_socket(fd);
  }

  if (fd < FILEX_FIRST_FD || fd >= FILEX_MAX_FDS || !g_fd_table[fd].in_use) {
	  errno = EBADF;
	  return -1;
  }

  //printf("Newlib: _close %d\n", fd);

  if (lock_fs() < 0) {
	  return -1;
  }

  filex_fd_t *entry = &g_fd_table[fd];

  if (entry->media == NULL) {
	  errno = EINVAL;
	  return -1;
  }

  UINT status = fx_file_close(&entry->file);

  if (status == FX_SUCCESS) {
	  /* Medium flushen, um Daten sicher wegzuschreiben */
	  fx_media_flush(entry->media);
	  free_fd(fd);
	  unlock_fs();
	  return 0;
  } else {
	  unlock_fs();
	  errno = EIO;
	  return -1;
  }
}

/*
 * _isatty
 *
 * stdin/stdout/stderr -> TTY
 */
int _isatty(int fd)
{
    if (fd >= 0 && fd < FILEX_FIRST_FD)
        return 1;
    return 0;
}

/*
 * _lseek
 *
 * Einfache Implementierung:
 *  - Unterstützt SEEK_SET und SEEK_CUR
 *  - SEEK_END kann bei Bedarf erweitert werden
 */
#define off_t int
off_t _lseek(int fd, off_t offset, int whence)
{
    if (fd < FILEX_FIRST_FD || fd >= FILEX_MAX_FDS || !g_fd_table[fd].in_use) {
        errno = EBADF;
        return -1;
    }

	//printf("Newlib: _lseek %d %d, %d\n", fd, offset, whence);

    if (lock_fs() < 0) {
        return -1;
    }

    filex_fd_t *entry = &g_fd_table[fd];

    if (entry->media == NULL) {
        errno = EINVAL;
        return -1;
    }

    FX_FILE    *fx    = &entry->file;
    UINT status;
    ULONG new_pos;

    switch (whence) {
    case SEEK_SET:
        status = fx_file_seek(fx, (ULONG)offset);
        new_pos = (ULONG)offset;
        break;

    case SEEK_CUR: {
        /* aktuelle Position + offset */
        ULONG current;
        /* FileX speichert aktuelle Position in file_current_file_offset */
        /* Achtung: Struktur ist intern – je nach Version kann sich das ändern.
         * Alternativ könnte man eine eigene Positionsverwaltung pflegen.
         */
        current = fx->fx_file_current_file_offset;
        new_pos = current + (LONG)offset;
        status  = fx_file_seek(fx, new_pos);
        break;
    }

    case SEEK_END: {
        /* Optional: Dateigröße über directory_information_get holen */
        ULONG size;
        UINT attributes, year, month, day, hour, minute, second;

        status = fx_directory_information_get(
                     entry->media,
                     (CHAR *)entry->name,
                     &attributes,
                     &size,
                     &year,
                     &month,
                     &day,
                     &hour,
                     &minute,
                     &second
                 );
        if (status != FX_SUCCESS) {
            unlock_fs();
            errno = EIO;
            return -1;
        }

        LONG pos = (LONG)size + (LONG)offset;
        if (pos < 0) {
            unlock_fs();
            errno = EINVAL;
            return -1;
        }

        new_pos = (ULONG)pos;
        status  = fx_file_seek(fx, new_pos);
        break;
    }

    default:
        unlock_fs();
        errno = EINVAL;
        return -1;
    }

    unlock_fs();

    if (status != FX_SUCCESS) {
        errno = EINVAL;
        return -1;
    }

    return (off_t)new_pos;
}

/*
 * _open
 *
 * Wandelt open()-Flags in FileX-Operationen um:
 *  - O_CREAT -> fx_file_create
 *  - O_TRUNC -> vorhandene Datei löschen
 *  - O_APPEND -> ans Dateiende seeken
 */
int _open(const char *name, int flags, int mode)
{
	//char filename[FILEX_FILENAME_SIZE];

    (void)mode; /* Mode wird im Embedded-Kontext oft ignoriert */

	//printf("Newlib: _open %s %d %d\n", name, flags, mode);

    if (name == NULL) {
        errno = EINVAL;
        return -1;
    }

    if (lock_fs() < 0) {
        return -1;
    }

    int fd = alloc_fd();
    if (fd < 0) {
        unlock_fs();
        errno = EMFILE; /* zu viele offene Dateien */
        return -1;
    }

    filex_fd_t *entry = &g_fd_table[fd];
    FX_FILE    *fx    = &entry->file;
    UINT        status;

    /* media pointer bestimmen */
    /* Dateiname merken (für spätere directory_information_get/SEEK_END) */
    MX_FileX_Eval_Path(name, &entry->media, entry->name, sizeof(entry->name));
    if(entry->media == NULL)
    {
        free_fd(fd);
        unlock_fs();
    	return -1;
    }
    //printf("_open: %p %s\n", entry->media, entry->name);
    entry->flags = flags;

    /* Datei ggf. erzeugen */
    if (flags & O_CREAT) {

        if (flags & O_TRUNC) {
            /* Vorhandene Datei löschen – Fehler ignorieren, falls nicht existiert */
            fx_file_delete(entry->media, (CHAR *)entry->name);
        }

        status = fx_file_create(entry->media, (CHAR *)entry->name);

        /* Wenn Datei schon existiert und O_EXCL gesetzt ist -> Fehler */
        if (status == FX_ALREADY_CREATED && (flags & O_EXCL)) {
            free_fd(fd);
            unlock_fs();
            errno = EEXIST;
            return -1;
        }

        /* andere Fehler */
        if ((status != FX_SUCCESS) && (status != FX_ALREADY_CREATED)) {
            free_fd(fd);
            unlock_fs();
            errno = EIO;
            return -1;
        }
    }

    /* Öffnungsmodus */
    UINT open_mode = FX_OPEN_FOR_READ;
    if ((flags & O_WRONLY) || (flags & O_RDWR)) {
        open_mode |= FX_OPEN_FOR_WRITE;
    }

    status = fx_file_open(entry->media, fx, (CHAR *)entry->name, open_mode);
    if (status != FX_SUCCESS) {
        free_fd(fd);
        unlock_fs();
        errno = EIO;
        return -1;
    }

    /* Falls O_TRUNC und nicht bereits gelöscht: Datei auf Länge 0 kürzen */
    if ((flags & O_TRUNC) && !(flags & O_CREAT)) {
        status = fx_file_truncate(fx, 0);
        if (status != FX_SUCCESS) {
            fx_file_close(fx);
            free_fd(fd);
            unlock_fs();
            errno = EIO;
            return -1;
        }
    }

    /* Anhängen: ans Dateiende seeken */
    if (flags & O_APPEND) {
        ULONG size;
        UINT attributes, year, month, day, hour, minute, second;

        status = fx_directory_information_get(
                     entry->media,
                     (CHAR *)entry->name,
                     &attributes,
                     &size,
                     &year,
                     &month,
                     &day,
                     &hour,
                     &minute,
                     &second
                 );

        if (status == FX_SUCCESS) {
            /* size = Dateigröße in Bytes */
            status = fx_file_seek(fx, size);
        }

        if (status != FX_SUCCESS) {
            fx_file_close(fx);
            free_fd(fd);
            unlock_fs();
            errno = EIO;
            return -1;
        }
    }

    unlock_fs();
    return fd;
}

